// // This module gates the power supply to a load based on the control signal. When ctrl is high, power_out is driven by data; when ctrl is low, power_out is driven by 0.
module power_gating (
    input wire ctrl,
    input wire [7:0] data,
    output wire [7:0] power_out
);

assign power_out = (ctrl) ? data : 8'b00000000;

endmodule
